changeSet.sql:
INSERT INTO creature_types (code, name_rusloc, name_engloc)
SELECT s.code, s.name_rusloc, NULLIF(s.name_engloc, '')
FROM seed_stg_creature_types s
WHERE NOT EXISTS (SELECT 1 FROM creature_types c WHERE c.code = s.code AND c.homebrew_id IS NULL);
DROP TABLE seed_stg_creature_types;

