INSERT INTO sources (code, name_rusloc, name_engloc, book_code)
SELECT s.code, s.name_rusloc, NULLIF(s.name_engloc, ''), NULLIF(s.book_code, '')
FROM seed_stg_sources s
WHERE NOT EXISTS (SELECT 1 FROM sources c WHERE c.code = s.code AND c.homebrew_id IS NULL);
DROP TABLE seed_stg_sources;
